params.spec:
{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "description": "One hexagon per EC2 instance, ordered impaired then healthy then unknown (worst first). Toggle Color by between Status, CPU utilization, or EBS writes (MB per CloudWatch period); metric views support Min, Max, Avg, and Last over the dashboard time range. Click any hexagon to filter the dashboard or open metrics for that instance.",
  "usermeta": {
    "x_ec2_hexmap": true
  },
  "padding": {
    "top": 10,
    "left": 10,
    "right": 10,
    "bottom": 15
  },
  "data": [
    {
      "name": "ts_probe",
      "url": {
        "%type%": "esql",
        "%context%": true,
        "%timefield%": "@timestamp",
        "query": "ROW round_key = CONCAT(TO_STRING(?_tstart), \"|\", TO_STRING(?_tend)), fetched_at = NOW()"
      }
    },
    {
      "name": "raw_all",
      "url": {
        "%type%": "esql",
        "%context%": true,
        "%timefield%": "@timestamp",
        "query": "SET unmapped_fields = \"nullify\";\nTS metrics-aws.ec2.otel-* | WHERE @timestamp >= ?_tstart AND @timestamp <= ?_tend\n AND InstanceId IS NOT NULL AND InstanceId != \"\" | STATS status_max = MAX(MAX_OVER_TIME(CASE(stat == \"Maximum\", `metrics.amazonaws.com/AWS/EC2/StatusCheckFailed`, NULL))), cpu_min = MIN(MIN_OVER_TIME(CASE(stat == \"Average\", `metrics.amazonaws.com/AWS/EC2/CPUUtilization`, NULL))), cpu_max = MAX(MAX_OVER_TIME(CASE(stat == \"Maximum\", `metrics.amazonaws.com/AWS/EC2/CPUUtilization`, NULL))), cpu_avg = AVG(AVG_OVER_TIME(CASE(stat == \"Average\", `metrics.amazonaws.com/AWS/EC2/CPUUtilization`, NULL))), cpu_last = MAX(LAST_OVER_TIME(CASE(stat == \"Maximum\", `metrics.amazonaws.com/AWS/EC2/CPUUtilization`, NULL))), ebs_w_min = MIN(MIN_OVER_TIME(CASE(stat == \"Average\", `metrics.amazonaws.com/AWS/EC2/EBSWriteBytes`, NULL))), ebs_w_max = MAX(MAX_OVER_TIME(CASE(stat == \"Average\", `metrics.amazonaws.com/AWS/EC2/EBSWriteBytes`, NULL))), ebs_w_avg = AVG(AVG_OVER_TIME(CASE(stat == \"Average\", `metrics.amazonaws.com/AWS/EC2/EBSWriteBytes`, NULL))), ebs_w_last = MAX(LAST_OVER_TIME(CASE(stat == \"Average\", `metrics.amazonaws.com/AWS/EC2/EBSWriteBytes`, NULL))), last_seen = MAX(@timestamp) BY instance_id = InstanceId\n, cloud.region | INLINE STATS latest_global = MAX(last_seen) | WHERE DATE_DIFF(\"minutes\", last_seen, latest_global) <= 5 | EVAL status_num = CASE(status_max > 0, 1, status_max == 0, 0, 2),\n status_label = CASE(status_max > 0, \"impaired\", status_max == 0, \"healthy\", \"Unknown\"),\n severity_rank = CASE(status_max > 0, 0, status_max == 0, 1, 2),\n ebs_w_min = ebs_w_min / 1048576,\n ebs_w_max = ebs_w_max / 1048576,\n ebs_w_avg = ebs_w_avg / 1048576,\n ebs_w_last = ebs_w_last / 1048576,\n round_key = CONCAT(TO_STRING(?_tstart), \"|\", TO_STRING(?_tend)),\n fetched_at = NOW() | KEEP instance_id, status_num, status_label, severity_rank,\n cpu_min, cpu_max, cpu_avg, cpu_last,\n ebs_w_min, ebs_w_max, ebs_w_avg, ebs_w_last,\n round_key, fetched_at | LIMIT 10000"
      }
    },
    {
      "name": "ranked_status",
      "source": "raw_all",
      "transform": [
        {
          "type": "collect",
          "sort": {
            "field": [
              "severity_rank",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_cpu_min",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.cpu_min == null ? 1e12 : -datum.cpu_min * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_cpu_max",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.cpu_max == null ? 1e12 : -datum.cpu_max * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_cpu_avg",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.cpu_avg == null ? 1e12 : -datum.cpu_avg * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_cpu_last",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.cpu_last == null ? 1e12 : -datum.cpu_last * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_ebs_w_min",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.ebs_w_min == null ? 1e12 : -datum.ebs_w_min * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_ebs_w_max",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.ebs_w_max == null ? 1e12 : -datum.ebs_w_max * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_ebs_w_avg",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.ebs_w_avg == null ? 1e12 : -datum.ebs_w_avg * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_ebs_w_last",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.ebs_w_last == null ? 1e12 : -datum.ebs_w_last * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "instance_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "active",
      "values": [],
      "on": [
        {
          "trigger": "ts_round !== '' && active_round !== '' && active_round !== ts_round",
          "remove": "true"
        },
        {
          "trigger": "metric === 'status' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_status')"
        },
        {
          "trigger": "metric === 'cpu' && agg === 'min' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_cpu_min')"
        },
        {
          "trigger": "metric === 'cpu' && agg === 'max' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_cpu_max')"
        },
        {
          "trigger": "metric === 'cpu' && agg === 'avg' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_cpu_avg')"
        },
        {
          "trigger": "metric === 'cpu' && agg === 'last' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_cpu_last')"
        },
        {
          "trigger": "metric === 'ebs_w' && agg === 'min' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_ebs_w_min')"
        },
        {
          "trigger": "metric === 'ebs_w' && agg === 'max' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_ebs_w_max')"
        },
        {
          "trigger": "metric === 'ebs_w' && agg === 'avg' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_ebs_w_avg')"
        },
        {
          "trigger": "metric === 'ebs_w' && agg === 'last' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_ebs_w_last')"
        }
      ]
    },
    {
      "name": "instances",
      "source": "active",
      "transform": [
        {
          "type": "formula",
          "as": "active_val",
          "expr": "metric=='status' ? null : (metric=='cpu'   ? (agg=='min' ? datum.cpu_min : agg=='max' ? datum.cpu_max : agg=='avg' ? datum.cpu_avg : datum.cpu_last)   : (agg=='min' ? datum.ebs_w_min : agg=='max' ? datum.ebs_w_max : agg=='avg' ? datum.ebs_w_avg : datum.ebs_w_last))"
        },
        {
          "type": "formula",
          "as": "index0",
          "expr": "datum.active_rank - 1"
        },
        {
          "type": "formula",
          "as": "col",
          "expr": "datum.index0 % gridCols"
        },
        {
          "type": "formula",
          "as": "row",
          "expr": "floor(datum.index0 / gridCols)"
        },
        {
          "type": "formula",
          "as": "x",
          "expr": "datum.col * gapX + (datum.row % 2 == 1 ? gapX / 2 : 0) + hexR + 5"
        },
        {
          "type": "formula",
          "as": "y",
          "expr": "datum.row * gapY + hexR + 5 + hexOffsetY"
        },
        {
          "type": "formula",
          "as": "hexSize",
          "expr": "hexR * hexR * 3.46"
        }
      ]
    },
    {
      "name": "status_counts",
      "source": "raw_all",
      "transform": [
        {
          "type": "aggregate",
          "groupby": [
            "status_num"
          ],
          "ops": [
            "count"
          ],
          "as": [
            "count"
          ]
        }
      ]
    },
    {
      "name": "status_legend",
      "values": [
        {
          "label": "Impaired",
          "val": 1
        },
        {
          "label": "Healthy",
          "val": 0
        },
        {
          "label": "Unknown",
          "val": 2
        }
      ],
      "transform": [
        {
          "type": "lookup",
          "from": "status_counts",
          "key": "status_num",
          "fields": [
            "val"
          ],
          "values": [
            "count"
          ],
          "as": [
            "count"
          ],
          "default": 0
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "idx"
          ]
        }
      ]
    },
    {
      "name": "util_counts",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "v",
          "expr": "agg == 'min' ? datum.cpu_min : agg == 'max' ? datum.cpu_max : agg == 'avg' ? datum.cpu_avg : datum.cpu_last"
        },
        {
          "type": "formula",
          "as": "bucket",
          "expr": "datum.v == null ? 3 : (datum.v >= 85 ? 2 : datum.v >= 60 ? 1 : 0)"
        },
        {
          "type": "aggregate",
          "groupby": [
            "bucket"
          ],
          "ops": [
            "count"
          ],
          "as": [
            "count"
          ]
        }
      ]
    },
    {
      "name": "util_legend_stops",
      "values": [
        {
          "label": "\u2265 85%",
          "val": 90,
          "bucket": 2,
          "is_nodata": false
        },
        {
          "label": "60 \u2013 84%",
          "val": 70,
          "bucket": 1,
          "is_nodata": false
        },
        {
          "label": "< 60%",
          "val": 0,
          "bucket": 0,
          "is_nodata": false
        },
        {
          "label": "Unknown",
          "val": null,
          "bucket": 3,
          "is_nodata": true
        }
      ],
      "transform": [
        {
          "type": "lookup",
          "from": "util_counts",
          "key": "bucket",
          "fields": [
            "bucket"
          ],
          "values": [
            "count"
          ],
          "as": [
            "count"
          ],
          "default": 0
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "idx"
          ]
        }
      ]
    },
    {
      "name": "vol_counts",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "v",
          "expr": "agg == 'min' ? datum.ebs_w_min : agg == 'max' ? datum.ebs_w_max : agg == 'avg' ? datum.ebs_w_avg : datum.ebs_w_last"
        },
        {
          "type": "formula",
          "as": "bucket",
          "expr": "datum.v == null ? 3 : (datum.v >= 500 ? 2 : datum.v >= 50 ? 1 : 0)"
        },
        {
          "type": "aggregate",
          "groupby": [
            "bucket"
          ],
          "ops": [
            "count"
          ],
          "as": [
            "count"
          ]
        }
      ]
    },
    {
      "name": "vol_legend_stops",
      "values": [
        {
          "label": "\u2265 500 MB",
          "val": 1000,
          "bucket": 2,
          "is_nodata": false
        },
        {
          "label": "50 \u2013 500 MB",
          "val": 100,
          "bucket": 1,
          "is_nodata": false
        },
        {
          "label": "< 50 MB",
          "val": 0,
          "bucket": 0,
          "is_nodata": false
        },
        {
          "label": "Unknown",
          "val": null,
          "bucket": 3,
          "is_nodata": true
        }
      ],
      "transform": [
        {
          "type": "lookup",
          "from": "vol_counts",
          "key": "bucket",
          "fields": [
            "bucket"
          ],
          "values": [
            "count"
          ],
          "as": [
            "count"
          ],
          "default": 0
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "idx"
          ]
        }
      ]
    },
    {
      "name": "spinner_dots",
      "values": [
        {
          "i": 0
        },
        {
          "i": 1
        },
        {
          "i": 2
        },
        {
          "i": 3
        },
        {
          "i": 4
        },
        {
          "i": 5
        },
        {
          "i": 6
        },
        {
          "i": 7
        }
      ]
    },
    {
      "name": "pills",
      "values": [
        {
          "id": "status",
          "label": "Status",
          "group": "metric",
          "x": 69,
          "w": 48
        },
        {
          "id": "cpu",
          "label": "CPU %",
          "group": "metric",
          "x": 125,
          "w": 58
        },
        {
          "id": "ebs_w",
          "label": "EBS Writes (MB)",
          "group": "metric",
          "x": 191,
          "w": 124
        },
        {
          "id": "min",
          "label": "Min",
          "group": "agg",
          "x": 425,
          "w": 36
        },
        {
          "id": "max",
          "label": "Max",
          "group": "agg",
          "x": 465,
          "w": 36
        },
        {
          "id": "avg",
          "label": "Avg",
          "group": "agg",
          "x": 505,
          "w": 36
        },
        {
          "id": "last",
          "label": "Last",
          "group": "agg",
          "x": 545,
          "w": 40
        }
      ]
    },
    {
      "name": "menu_items_data",
      "values": [
        {
          "id": "filter",
          "label": "Filter dashboard by this instance",
          "idx": 0
        },
        {
          "id": "metrics",
          "label": "View instance metrics in Discover",
          "idx": 1
        }
      ]
    },
    {
      "name": "menu_visible",
      "values": [
        {
          "_": 0
        }
      ],
      "transform": [
        {
          "type": "filter",
          "expr": "selected_instance != null"
        }
      ]
    },
    {
      "name": "menu_items_visible",
      "source": "menu_items_data",
      "transform": [
        {
          "type": "filter",
          "expr": "selected_instance != null"
        }
      ]
    }
  ],
  "signals": [
    {
      "name": "metric",
      "value": "status",
      "on": [
        {
          "events": "@pill_bg:click",
          "update": "datum.group === 'metric' ? datum.id : metric"
        }
      ]
    },
    {
      "name": "agg",
      "value": "last",
      "on": [
        {
          "events": "@pill_bg:click",
          "update": "(datum.group === 'agg' && !(metric === 'status')) ? datum.id : agg"
        }
      ]
    },
    {
      "name": "groupHeaderH",
      "value": 20
    },
    {
      "name": "groupGap",
      "value": 10
    },
    {
      "name": "group_by",
      "value": "none"
    },
    {
      "name": "len_raw",
      "update": "length(data('raw_all'))"
    },
    {
      "name": "len_active",
      "update": "length(data('active'))"
    },
    {
      "name": "ts_round",
      "update": "data('ts_probe')[0] ? data('ts_probe')[0].round_key : ''"
    },
    {
      "name": "time_from",
      "update": "ts_round !== '' && indexof(ts_round, '|') > 0 ? slice(ts_round, 0, indexof(ts_round, '|')) : ''"
    },
    {
      "name": "time_to",
      "update": "ts_round !== '' && indexof(ts_round, '|') > 0 ? slice(ts_round, indexof(ts_round, '|') + 1) : ''"
    },
    {
      "name": "g_param",
      "update": "time_from !== '' && time_to !== '' ? '_g=(time:(from:%27' + time_from + '%27,to:%27' + time_to + '%27))&' : ''"
    },
    {
      "name": "raw_round",
      "update": "data('raw_all')[0] ? data('raw_all')[0].round_key : ''"
    },
    {
      "name": "active_round",
      "update": "raw_round"
    },
    {
      "name": "raw_fetched_str",
      "update": "data('raw_all')[0] ? data('raw_all')[0].fetched_at : ''"
    },
    {
      "name": "active_fetched",
      "update": "raw_fetched_str !== '' ? toDate(raw_fetched_str) : 0"
    },
    {
      "name": "tick",
      "value": 0,
      "on": [
        {
          "events": {
            "type": "timer",
            "throttle": 100
          },
          "update": "now()"
        }
      ]
    },
    {
      "name": "url_change_at",
      "value": 0,
      "on": [
        {
          "events": {
            "source": "window",
            "type": "hashchange"
          },
          "update": "now()"
        },
        {
          "events": {
            "source": "window",
            "type": "popstate"
          },
          "update": "now()"
        }
      ]
    },
    {
      "name": "fetch_tracker",
      "init": "{seen: 0, arrived_at: 0}",
      "on": [
        {
          "events": {
            "signal": "tick"
          },
          "update": "active_fetched > 0 && active_fetched !== fetch_tracker.seen ? {seen: active_fetched, arrived_at: tick} : fetch_tracker"
        }
      ]
    },
    {
      "name": "loading_raw",
      "update": "len_active === 0 || ts_round === '' || active_round === '' || active_round !== ts_round || (url_change_at > 0 && fetch_tracker.arrived_at < url_change_at)"
    },
    {
      "name": "loading_started_at",
      "value": 0,
      "on": [
        {
          "events": {
            "signal": "tick"
          },
